  const [error, setError] = useState('');
  const googleBtnRef = useRef<HTMLDivElement>(null);

  // Initialize Google Identity Services
  useEffect(() => {
    /* global google */
    if (typeof window !== 'undefined' && (window as any).google) {
      const google = (window as any).google;

      google.accounts.id.initialize({
        // Placeholder Client ID - in production, this should be replaced with a real ID from Google Cloud Console
        client_id: "774321689405-c8m6f1f4p1f0v7n7g6n0p8n8n8n8n8n8.apps.googleusercontent.com", 
        callback: handleGoogleCredentialResponse,
        auto_select: false,
        cancel_on_tap_outside: true,
      });

      // Render the official Google button into our hidden container
      // This ensures we can trigger the flow while maintaining some UI control
      if (googleBtnRef.current) {
        google.accounts.id.renderButton(googleBtnRef.current, {
          type: 'standard',
          theme: 'outline',
          size: 'large',
          text: 'signin_with',
          shape: 'rectangular',
          width: 250
        });
      }
    }
  }, []);

  const handleGoogleCredentialResponse = (response: any) => {
    setSocialLoading('google');
    const userData = parseJwt(response.credential);

    if (userData) {
      setTimeout(() => {
        const authenticatedUser: User = {
          id: `google_${userData.sub}`,
          email: userData.email,
          name: userData.name,
          role: UserRole.STUDENT,
        };
        onLogin(authenticatedUser);
        setSocialLoading(null);
      }, 1000);
    } else {
      setError('Failed to verify Google account.');
      setSocialLoading(null);
    }
  };

  const handleGoogleClick = () => {
    setSocialLoading('google');
    // Trigger the One Tap prompt as a secondary method
    try {
      (window as any).google.accounts.id.prompt((notification: any) => {
        if (notification.isNotDisplayed() || notification.isSkippedMoment()) {
          // If One Tap fails or is skipped, we rely on the rendered button
          console.log('One Tap skipped or not displayed');
          setSocialLoading(null);
          // Alert user to click the standard button if the prompt didn't appear
          setError('Please use the Google Sign-in button below.');
        }
      });
    } catch (e) {
      setSocialLoading(null);
      setError('Google Sign-in is initializing. Please try again.');
    }
