                  <Compass size={24} />
               </div>
               <span className="font-bold text-2xl text-indigo-600">SKILL PILOT</span>
               <span className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">by RK FOUNDATIONS</span>
