                  type="file" 
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept="image/*,.pdf"
                  className="hidden"
                />

                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${selectedFile ? 'border-green-400 bg-green-50' : 'border-gray-200 hover:border-indigo-400 hover:bg-indigo-50/50'}`}
                >
                  {selectedFile ? (
                    <div className="flex flex-col items-center">
                      <FileText size={32} className="text-green-500 mb-2" />
                      <p className="text-xs font-bold text-green-700 truncate w-full px-4">{selectedFile.name}</p>
                      <button className="text-[10px] text-indigo-600 font-bold mt-2 hover:underline">Change file</button>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center">
                      <Upload size={32} className="text-gray-300 mb-2" />
                      <p className="text-xs text-gray-500">Click to upload receipt (JPG, PNG, PDF)</p>
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 flex gap-3">
              <AlertCircle size={18} className="text-amber-500 flex-shrink-0" />
              <p className="text-[11px] text-amber-700 leading-tight">
                Verification usually takes 5-10 minutes. Our admin team will verify your receipt and activate your Pro status.
              </p>
            </div>

            <button 
              onClick={handleSubmit}
              disabled={!selectedFile || isProcessing}
              className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-3 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 disabled:opacity-50 disabled:shadow-none"
            >
              {isProcessing ? (
                <><Loader2 size={20} className="animate-spin" /> VERIFYING RECEIPT...</>
              ) : (
                <>SUBMIT FOR VERIFICATION <CheckCircle2 size={20} /></>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PaymentModal;

import React, { useState, useEffect } from 'react';
import { User, ModuleType } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import ModuleView from './components/ModuleView';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import PaymentModal from './components/PaymentModal';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<'dashboard' | 'module'>('dashboard');
  const [selectedModule, setSelectedModule] = useState<ModuleType | null>(null);
  const [loading, setLoading] = useState(true);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [isVerifyingPayment, setIsVerifyingPayment] = useState(false);

  useEffect(() => {
    // Check local storage for session
    const storedUser = localStorage.getItem('edu_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setLoading(false);
  }, []);

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('edu_user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('edu_user');
    setCurrentView('dashboard');
    setSelectedModule(null);
  };

  const handleStartUpgrade = () => {
    setShowPaymentModal(true);
  };

  const handleReceiptUpload = (file: File) => {
    setIsVerifyingPayment(true);

    // Simulate admin verification process
    setTimeout(() => {
      if (user) {
        const updatedUser = { 
          ...user, 
          isPremium: true, 
          isPendingVerification: false 
        };
        setUser(updatedUser);
        localStorage.setItem('edu_user', JSON.stringify(updatedUser));
        setIsVerifyingPayment(false);
        setShowPaymentModal(false);
        alert("Receipt Verified! Your Pro Account is now active. Enjoy premium features!");
      }
    }, 3000);
  };

  const navigateToModule = (module: ModuleType) => {
    setSelectedModule(module);
    setCurrentView('module');
  };

  const navigateHome = () => {
    setCurrentView('dashboard');
    setSelectedModule(null);
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
      </div>
    );
  }

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex bg-gray-50">
      <Sidebar 
        activeModule={selectedModule} 
        onNavigate={navigateToModule} 
        onHome={navigateHome} 
        isPremium={user.isPremium}
        isPending={user.isPendingVerification}
        onUpgrade={handleStartUpgrade}
      />

      <div className="flex-1 flex flex-col min-h-screen">
        <Navbar user={user} onLogout={handleLogout} onHome={navigateHome} />

        <main className="flex-1 p-6 md:p-10 overflow-auto">
          {currentView === 'dashboard' ? (
            <Dashboard onSelectModule={navigateToModule} />
          ) : (
            selectedModule && <ModuleView type={selectedModule} onBack={navigateHome} user={user} onUpgrade={handleStartUpgrade} />
          )}
        </main>

        <footer className="bg-white border-t p-4 text-center text-gray-500 text-sm">
          &copy; {new Date().getFullYear()} SKILL PILOT by RK FOUNDATIONS. All rights reserved.
        </footer>
      </div>

      {showPaymentModal && (
        <PaymentModal 
          onClose={() => setShowPaymentModal(false)} 
          onUpload={handleReceiptUpload}
          isProcessing={isVerifyingPayment}
        />
      )}
    </div>
  );
};

export default App;

